1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	
23	export function quote(customer: Customer, items: Item[]): number {
24	  if (items.length === 0) return PROCESSING_FEE;
25	  const basePremium = BASE_PREMIUMS[items[0].type];
26	  return basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
27	}
